package com.taskmind.backend.task.interfaces.rest; import com.taskmind.backend.security.AuthenticatedUserResolver; import com.taskmind.backend.task.application.TaskLinkApplicationService; import java.util.UUID; import org.springframework.http.ResponseEntity; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/v1/task-links") public class TaskLinkByIdController{private final TaskLinkApplicationService service;private final AuthenticatedUserResolver users;public TaskLinkByIdController(TaskLinkApplicationService s,AuthenticatedUserResolver u){service=s;users=u;}@DeleteMapping("/{id}")public ResponseEntity<Void> delete(@PathVariable UUID id,@RequestHeader(value="X-User-Id",required=false)UUID uid,@RequestHeader(value="X-User-Roles",required=false)String roles,Authentication auth){service.delete(users.resolve(auth,uid,roles),id);return ResponseEntity.noContent().build();}}
